set truncationmaxrecords=10000;
set truncationmaxsize=67108864;
let daysInRange = toreal({TimeRange:seconds}) / 86400.0;
let userRate = toreal('{EffectiveAnalyticsRate}');
let userCommit = toreal('{CommittedGBPerDay}');
let modelRate = case('{PricingModel}' == 'CT50', 3.23, '{PricingModel}' == 'CT100', 2.96, '{PricingModel}' == 'CT200', 2.85, '{PricingModel}' == 'CT300', 2.77, '{PricingModel}' == 'CT400', 2.73, '{PricingModel}' == 'CT500', 2.61, '{PricingModel}' == 'CT1000', 2.41, '{PricingModel}' == 'CT2000', 2.22, '{PricingModel}' == 'CT5000', 2.11, 4.30);
let modelCommit = case('{PricingModel}' == 'CT50', 50.0, '{PricingModel}' == 'CT100', 100.0, '{PricingModel}' == 'CT200', 200.0, '{PricingModel}' == 'CT300', 300.0, '{PricingModel}' == 'CT400', 400.0, '{PricingModel}' == 'CT500', 500.0, '{PricingModel}' == 'CT1000', 1000.0, '{PricingModel}' == 'CT2000', 2000.0, '{PricingModel}' == 'CT5000', 5000.0, 0.0);
let priceAnalytics = iif(userRate > 0, userRate, modelRate);
let commitGB = iif(userCommit > 0, userCommit, modelCommit);
let base = Usage
    | where TimeGenerated {TimeRange}
    | where IsBillable == true
    | summarize BillableGB = sum(Quantity) / 1000.0
    | extend DailyAvgGB = BillableGB / daysInRange
        , MonthlyGB = (BillableGB / daysInRange) * 30.0
        , AnnualCost = ((BillableGB / daysInRange) * 365.0) * priceAnalytics
        , MonthlyCost = ((BillableGB / daysInRange) * 30.0) * priceAnalytics
        , CommitmentStatus = case(commitGB == 0, strcat('N/A (', '{PricingModel}', ')')
            , (BillableGB / daysInRange) > commitGB, strcat('Above by ', round((BillableGB / daysInRange) - commitGB, 1), ' GB/day')
            , (BillableGB / daysInRange) < commitGB * 0.8, strcat('Under-using (', round((BillableGB / daysInRange) / commitGB * 100.0, 0), '% of ', commitGB, ' GB/day)')
            , strcat('Within commitment (', commitGB, ' GB/day)'));
union
    (base | project SortOrder=1, Metric='Daily volume',           ValueText=strcat(tostring(round(DailyAvgGB, 2)), ' GB'),                                Subtitle=strcat('Avg over last ', tostring(toint(daysInRange)), ' days')),
    (base | project SortOrder=2, Metric='Monthly volume',         ValueText=strcat(tostring(round(MonthlyGB, 2)), ' GB'),                                 Subtitle='Projected 30-day ingestion'),
    (base | project SortOrder=3, Metric='Effective rate',         ValueText=strcat(tostring(round(priceAnalytics, 2)), ' {Currency}/GB'),                 Subtitle=strcat('Based on ', '{PricingModel}', ' pricing model')),
    (base | project SortOrder=4, Metric='Monthly Analytics cost', ValueText=strcat(tostring(round(MonthlyCost, 2)), ' {Currency}'),                       Subtitle=strcat('Annualised: ', tostring(round(AnnualCost, 0)), ' {Currency}')),
    (base | project SortOrder=5, Metric='Commitment status',      ValueText=CommitmentStatus,                                                              Subtitle='Daily volume vs commitment-tier floor')
| order by SortOrder asc
| project Metric, ValueText, Subtitle

