set truncationmaxrecords=10000;
set truncationmaxsize=67108864;
let daysInRange = toreal({TimeRange:seconds}) / 86400.0;
let userRate = toreal('{EffectiveAnalyticsRate}');
let modelRate = case('{PricingModel}' == 'CT50', 3.23, '{PricingModel}' == 'CT100', 2.96, '{PricingModel}' == 'CT200', 2.85, '{PricingModel}' == 'CT300', 2.77, '{PricingModel}' == 'CT400', 2.73, '{PricingModel}' == 'CT500', 2.61, '{PricingModel}' == 'CT1000', 2.41, '{PricingModel}' == 'CT2000', 2.22, '{PricingModel}' == 'CT5000', 2.11, 4.30);
let priceAnalytics = iif(userRate > 0, userRate, modelRate);
let priceLakeIngest = toreal('{LakeIngestPricePerGB}');
let priceLakeProc = toreal('{LakeProcessingPricePerGB}');
let priceLakeStore = toreal('{LakeStoragePricePerGBMonth}');
let lakeRetentionDays = toreal('{TargetLakeRetentionDays}');
let compressionRatio = toreal('{CompressionRatio}');
// Hard-incompatible — Microsoft excludes these from Data Lake entirely
let notSupportedInLake = dynamic([
 'AzureDiagnostics','AzureMetrics'
]);
// Sentinel feature-backing — must stay Analytics for Sentinel to function
let sentinelFeatureTables = dynamic([
 'SecurityAlert','SecurityIncident','SecurityRecommendation'
 ,'ThreatIntelligenceIndicator','ThreatIntelIndicators','ThreatIntelObjects'
 ,'Watchlist','SentinelHealth','SentinelAudit','HuntingBookmark','SecurityBaseline','SecurityBaselineSummary'
]);
// UEBA — feature-backing but tracked separately for reporting clarity
let uebaTables = dynamic([
 'BehaviorAnalytics','IdentityInfo','UserPeerAnalytics','BehaviorAnalyticsCloudActivityLogs'
]);
// Log Analytics platform/system tables — operational, not security data
let systemTables = dynamic([
 'Heartbeat','Usage','Operation','LAQueryLogs','LASummaryLogs','ProtectionStatus','ComputerGroup'
]);
// Classic V1 _CL tables auto-detected from ARM (tableSubType='Classic') — these are NOT lake-compatible
let classicV1Tables = dynamic([{ClassicV1Tables}]);
// DCR-based _CL tables auto-detected from ARM (tableSubType='DataCollectionRuleBased')
let dcrCustomTables = dynamic([{DcrCustomTables}]);
// Tables on Basic / Auxiliary plans auto-detected from ARM
let basicPlanTables = dynamic([{BasicPlanTables}]);
let auxiliaryPlanTables = dynamic([{AuxiliaryPlanTables}]);
Usage
| where TimeGenerated {TimeRange}
| where IsBillable == true
| summarize BillableGB = sum(Quantity) / 1000.0, Solution = take_any(Solution) by DataType
| extend MonthlyGB = (BillableGB / daysInRange) * 30.0
| extend AnalyticsMonthlyCost = MonthlyGB * priceAnalytics
| extend LakeIngestCost = MonthlyGB * priceLakeIngest
 , LakeProcCost = MonthlyGB * priceLakeProc
 , LakeStorageCost = (MonthlyGB * (lakeRetentionDays / 30.0) / compressionRatio) * priceLakeStore
| extend LakeMonthlyCost = LakeIngestCost + LakeProcCost + LakeStorageCost
| extend MonthlySaving = AnalyticsMonthlyCost - LakeMonthlyCost
 , SavingPct = iif(AnalyticsMonthlyCost > 0, round((AnalyticsMonthlyCost - LakeMonthlyCost) / AnalyticsMonthlyCost * 100.0, 1), real(0))
| extend Plan = case(
 DataType in (basicPlanTables), 'Basic'
 , DataType in (auxiliaryPlanTables), 'Auxiliary'
 , 'Analytics')
| extend IngestionMode = case(
 DataType in (classicV1Tables), 'Classic V1'
 , DataType in (dcrCustomTables), 'DCR-based'
 , DataType endswith '_CL', 'Custom (unknown)'
 , 'Standard')
| extend Category = case(
 DataType in (notSupportedInLake), 'Not supported in Lake'
 , DataType in (uebaTables), 'UEBA (Analytics-only)'
 , DataType in (sentinelFeatureTables),'Sentinel feature dependency'
 , DataType in (systemTables), 'System table'
 , DataType in (classicV1Tables), 'Custom log V1 (not supported)'
 , Plan == 'Basic', 'Basic plan (convert first)'
 , DataType endswith '_CL', 'Custom log DCR-based'
 , 'Supported')
| extend NotEligibleForLake = Category in ('Not supported in Lake','UEBA (Analytics-only)','Sentinel feature dependency','System table','Custom log V1 (not supported)','Basic plan (convert first)')
// Two valid migration strategies for ELIGIBLE tables:
// - Lake-only: table has zero active rules; full migration
// - Hybrid tier: table has active rules; keep recent in Analytics for detection window, archive older to Lake via KQL Job / Summary rule
// The workbook can't auto-detect rules per table without ARM join — recommendation flags eligibility, user verifies rules via Rule Coverage tab before choosing strategy
| extend Candidate = case(
 Category == 'Not supported in Lake', 'Not supported - keep in Analytics'
 , Category == 'UEBA (Analytics-only)', 'UEBA - keep in Analytics'
 , Category == 'Sentinel feature dependency', 'Sentinel feature - keep in Analytics'
 , Category == 'System table', 'System table - skip'
 , Category == 'Custom log V1 (not supported)', 'Classic V1 — migrate ingestion to DCR before any tier decision'
 , Category == 'Basic plan (convert first)', 'Basic plan - convert to Analytics first'
 , Category == 'Custom log DCR-based' and MonthlySaving > 0,
 'Eligible - click row to see detection rules'
 , Category == 'Custom log DCR-based', 'DCR-based custom log — no saving at current model'
 , MonthlySaving > 0, 'Eligible - click row to see detection rules'
 , 'No saving at current pricing')
// Null out lake costs and savings for tables that physically can't be moved
| extend LakeMonthlyCost = iif(NotEligibleForLake, real(null), LakeMonthlyCost)
 , MonthlySaving = iif(NotEligibleForLake, real(null), MonthlySaving)
 , SavingPct = iif(NotEligibleForLake, real(null), SavingPct)
| order by MonthlySaving desc nulls last
| extend Status = case(
    Category == 'Not supported in Lake',           '❌',
    Category == 'UEBA (Analytics-only)',           '❌',
    Category == 'Sentinel feature dependency',     '❌',
    Category == 'System table',                    '❌',
    Category == 'Custom log V1 (not supported)',   '⚠️',
    Category == 'Basic plan (convert first)',      '⚠️',
    Category == 'Custom log DCR-based' and MonthlySaving > 0, '✅',
    MonthlySaving > 0,                              '✅',
    '')
| project ['Table']=DataType
 , Solution
 , Category
 , Plan
 , ['Ingestion mode']=IngestionMode
 , Status, ['Recommendation']=Candidate
 , ['GB/month']=round(MonthlyGB,2)
 , ['Analytics cost ({Currency})']=round(AnalyticsMonthlyCost,2)
 , ['Lake cost ({Currency})']=round(LakeMonthlyCost,2)
 , ['Monthly saving ({Currency})']=round(MonthlySaving,2)
 , ['Saving %']=SavingPct

